SELECT production_order.* ,material.name as materialName, customer.name as customerName FROM production_order
JOIN material ON material.`code`=production_order.material_code
  LEFT JOIN customer ON customer.`code`=production_order.customer_code
  where production_order.delete_flag!=1 and material.delete_flag!=1 AND (customer.delete_flag!=1 OR customer.delete_flag IS NULL)

    And production_order_code =#{productionOrderCode}


    And production_order_name LIKE CONCAT('%', #{productionOrderName}, '%')


    And production_order_source =#{productionOrderSource}


    And material_code =#{materialCode}


    And material.name LIKE CONCAT('%', #{materialName}, '%')


    And customer_code = #{customerCode}


    And customer.name LIKE CONCAT('%', #{customerName}, '%')


    And production_order_type = #{productionOrderType}


    And production_order.status = #{status}


    And request_date = #{requestDate}

SELECT production_order.* ,material.name as materialName, customer.name as customerName FROM production_order
JOIN material ON material.`code`=production_order.material_code
LEFT JOIN customer ON customer.`code`=production_order.customer_code
where production_order.delete_flag!=1 and material.delete_flag!=1
AND (customer.delete_flag!=1 OR customer.delete_flag IS NULL) and production_order.status=41

    And production_order_code =#{productionOrderCode}


    And production_order_name LIKE CONCAT('%', #{productionOrderName}, '%')


    And production_order_source =#{productionOrderSource}


    And material_code =#{materialCode}


    And material.name LIKE CONCAT('%', #{materialName}, '%')


    And customer_code = #{customerCode}


    And customer.name LIKE CONCAT('%', #{customerName}, '%')


    And production_order_type = #{productionOrderType}


    And production_order.status = #{status}


    And request_date = #{requestDate}
